% multiplicative quotient through \lstinline{Additive}: the value at \(S\) is
% \lstinline{AddCommGrpCat.of (Additive (Pic (C ×_k S) ⧸ ...))} and the action on
% morphisms is \lstinline{MonoidHom.toAdditive (PicardFunctor.quotMap C f.unop)} bundled via
% \lstinline{AddCommGrpCat.ofHom}. The underlying type is def-equal to the multiplicative
% quotient (\lstinline{Additive G} is the same type as \lstinline{G} as a Lean type), so the
% "agrees on the nose with PicardFunctor" remark above is correct at the type level; only the
% group-structure instance differs (additive vs. multiplicative). The
% \lstinline{PicardFunctorAb_forget_obj} simp lemma below records this object-level
% definitional identity.

\begin{lemma}[Forget-evaluation simp lemma]
  \label{lem:PicardFunctorAb_forget_obj}
  \lean{AlgebraicGeometry.Scheme.PicardFunctorAb_forget_obj}
  \uses{def:Pic_functorAb, def:PicardFunctorAb_forgetCompare}
  For every $S \in (\Sch_k)^{\mathrm{op}}$,
  \[
    (\forget\,\AddCommGrpCat).\mathrm{obj}\,\bigl((\PicardFunctorAb\, C).\mathrm{obj}\,S\bigr) \;=\; (\PicardFunctor\, C).\mathrm{obj}\,S.
  \]
\end{lemma}

\begin{proof}
  \uses{def:Pic_functorAb, def:PicardFunctorAb_forgetCompare}
  Definitionally true: both sides are the underlying carrier of the quotient $\Pic(C \times_k S) / p_S^*\Pic(S)$. The closure is \lstinline{rfl}.
\end{proof}

