\subsection{The structure sheaf as a sheaf of $k$-modules}

\begin{definition}[Structure sheaf as a sheaf of $k$-modules]
  \label{def:Scheme_toModuleKSheaf}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf}
  \uses{def:Scheme_toModuleKPresheaf, thm:Scheme_toModuleKPresheaf_isSheaf}
  \leanok
  Bundle Definition~\ref{def:Scheme_toModuleKPresheaf} and Theorem~\ref{thm:Scheme_toModuleKPresheaf_isSheaf} into the sheaf
  \[
    \mathtt{toModuleKSheaf}\,C \;\colon\; \Sheaf\bigl(\opens(C.\mathrm{left}.\mathrm{toTopCat}),\ \ModuleCat\,k\bigr).
  \]
\end{definition}

\subsection{Forget-and-recover: bridging $\toModuleKSheaf$ and $\toAbSheaf$}

The iter-007 polish track adds two consumer-facing helpers. The first records that, after forgetting from $\ModuleCat\,k$ to $\AddCommGrpCat$ via $\forget_2$, the iter-006 sheaf agrees on the nose with the iter-004 abelian-group-level structure sheaf $\toAbSheaf\,C.\mathrm{left}$. This is what allows downstream consumers (cohomology comparisons, derived-functor identifications) to transport between the two flavours.

\begin{definition}[Forget-and-recover natural iso for $\toModuleKSheaf$]
  \label{def:Scheme_toModuleKSheaf_forgetCompare}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf_forgetCompare}
  \uses{def:Scheme_toModuleKSheaf, def:Scheme_toAbSheaf}
  Let $C : \Over\,(\Spec\,(\CommRingCat\,k))$. Then there is an isomorphism of sheaves of abelian groups
  \[
    (\sheafCompose\,(\opens.\mathrm{grothendieckTopology}\,C.\mathrm{left}.\mathrm{toTopCat})\,(\forget_2\,(\ModuleCat\,k)\,\AddCommGrpCat)).\mathrm{obj}\,(\toModuleKSheaf\,C) \;\cong\; \toAbSheaf\,C.\mathrm{left}.
  \]
\end{definition}

\begin{proof}
  \uses{def:Scheme_toModuleKSheaf, def:Scheme_toAbSheaf}
  Definitionally true: both sides have $(\AddCommGrpCat.\mathrm{of}\,(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{obj}\,U))$ at every $U$ (via the $\forget_2 (\ModuleCat\,k)\,\AddCommGrpCat$ on the LHS and the iter-004 $(\sheafCompose\,J\,(\forget_2\,\CommRingCat\,\RingCat\,\circ\,\forget_2\,\RingCat\,\AddCommGrpCat)).\mathrm{obj}\,C.\mathrm{left}.\mathrm{sheaf}$ unfolding on the RHS), and the action on morphisms is the underlying $C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}$ on both sides. The closure is \lstinline{Iso.refl _}; probe-confirmed (iteration~007 plan-agent \lstinline{lean_run_code}).
\end{proof}

\begin{lemma}[Object-evaluation simp lemma for $\toModuleKPresheaf$]
  \label{lem:Scheme_toModuleKPresheaf_obj}
  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_obj}
  \uses{def:Scheme_toModuleKPresheaf}
  For every $U \in \opens(C.\mathrm{left}.\mathrm{toTopCat})^{\mathrm{op}}$,
  \[
    (\toModuleKPresheaf\,C).\mathrm{obj}\,U \;=\; \ModuleCat.\mathrm{of}\,k\,(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{obj}\,U).
  \]
\end{lemma}

\begin{proof}
  \uses{def:Scheme_toModuleKPresheaf}
  Definitionally true by the construction of $\toModuleKPresheaf$ (Definition~\ref{def:Scheme_toModuleKPresheaf}). The closure is \lstinline{rfl}; the lemma is tagged \lstinline{@[simp]} so consumers can rewrite without unfolding the constructor.
\end{proof}

